const body = $input.first().json.body || $input.first().json;
const projectId = body.projectId || 'unknown';
const productIdea = body.productIdea || '';
const runId = body.runId || `research-${Date.now()}`;

if (!productIdea) {
  throw new Error('productIdea is required in the request body');
}

const words = productIdea.toLowerCase().split(/\s+/);
const stopWords = new Set(['the', 'a', 'an', 'and', 'or', 'but', 'is', 'are', 'was', 'were', 'be', 'been', 'for', 'with', 'that', 'this', 'to', 'of', 'in', 'on', 'at', 'by']);
const keywords = words.filter(w => w.length > 2 && !stopWords.has(w));

const domain = keywords.slice(0, 3).join(' ');

const searchQueries = [
  `${domain} market analysis competitors`,
  `${domain} user pain points jobs to be done`,
  `${domain} existing solutions comparison`,
  `${domain} technology trends ${new Date().getFullYear()}`,
  `${domain} pricing models SaaS`
];

const targetAudience = {
  primary: `Users who need ${domain}`,
  painPoints: [
    `Current solutions for ${domain} are too complex`,
    `Existing tools lack integration capabilities`,
    `High cost of current ${domain} solutions`
  ],
  jobsToBeDone: [
    `Simplify ${domain} workflow`,
    `Reduce time spent on ${domain} tasks`,
    `Get better insights from ${domain} data`
  ]
};

return [{
  json: {
    projectId,
    productIdea,
    runId,
    keywords,
    domain,
    searchQueries,
    targetAudience
  }
}];

const input = $input.first().json;
const selectedOption = input.options.find(o => o.id === input.recommendation.preferred) || input.options[0];

const requirements = {
  functional: [
    {
      id: 'FR-001',
      title: `Core ${input.domain} functionality`,
      priority: 'must-have',
      description: `Implement the primary job-to-be-done: ${input.targetAudience.jobsToBeDone[0]}`,
      acceptanceCriteria: [
        'User can complete core workflow end-to-end',
        'Response time < 2 seconds for primary actions',
        'Works on desktop and mobile viewports'
      ]
    },
    {
      id: 'FR-002',
      title: 'User onboarding flow',
      priority: 'must-have',
      description: 'First-time user experience that demonstrates value within 60 seconds',
      acceptanceCriteria: [
        'New user reaches "aha moment" within 3 steps',
        'No mandatory signup required for initial exploration',
        'Progress is saved when user creates account'
      ]
    },
    {
      id: 'FR-003',
      title: 'Data export and portability',
      priority: 'should-have',
      description: 'Users can export their data in standard formats',
      acceptanceCriteria: [
        'Export to CSV and JSON supported',
        'Export completes within 30 seconds for typical datasets',
        'Exported data is complete and re-importable'
      ]
    }
  ],
  nonFunctional: [
    { id: 'NFR-001', category: 'performance', requirement: 'Page load time < 3 seconds on 3G', priority: 'must-have' },
    { id: 'NFR-002', category: 'security', requirement: 'OWASP Top 10 compliance', priority: 'must-have' },
    { id: 'NFR-003', category: 'accessibility', requirement: 'WCAG 2.1 AA compliance', priority: 'must-have' },
    { id: 'NFR-004', category: 'scalability', requirement: 'Handle 1000 concurrent users', priority: 'should-have' },
    { id: 'NFR-005', category: 'availability', requirement: '99.5% uptime SLA', priority: 'should-have' }
  ],
  constraints: [
    `Time to market: ${selectedOption.timeToMarket}`,
    `Effort estimate: ${selectedOption.estimatedEffort}`,
    `Risk level: ${selectedOption.riskLevel}`,
    'Must comply with GDPR for EU users',
    'Self-hostable option required for enterprise tier'
  ]
};

const researchSummary = {
  projectId: input.projectId,
  runId: input.runId,
  productIdea: input.productIdea,
  domain: input.domain,
  targetAudience: input.targetAudience,
  competitiveAnalysis: {
    searchQueries: input.searchQueries,
    note: 'Queries prepared for manual or automated competitive research'
  },
  options: input.options,
  recommendation: input.recommendation,
  requirements
};

return [{
  json: researchSummary
}];

// Auto-converted from Set v3 (n8n 2.15.x SetV2 node crashes at SetV2.node.ts:352)
return [{ json: {
  "workflow": "hive-product-research",
  "endpoint": "product-research",
  "kind": "structured_loop",
  "status": "completed",
  "receivedAt": $now.toISO(),
  "timeoutMs": 120000,
  "success": true,
  "result": JSON.stringify({ projectId: $('Structure Requirements').first().json.projectId, runId: $('Structure Requirements').first().json.runId, domain: $('Structure Requirements').first().json.domain, optionCount: $('Structure Requirements').first().json.options.length, recommendedOption: $('Structure Requirements').first().json.recommendation.preferred, requirementCount: $('Structure Requirements').first().json.requirements.functional.length + $('Structure Requirements').first().json.requirements.nonFunctional.length })
} }];

// Auto-converted from Set v3 (n8n 2.15.x SetV2 node crashes at SetV2.node.ts:352)
return [{ json: {
  "research_run_id": $json.run_id || ('hive_research_' + Date.now())
} }];
